import React, { useState } from "react";
import { NOME_APP, CSS } from "./utils/constants";
import { LS } from "./utils/helpers";

// 1. FUNÇÃO PRINCIPAL (O Cérebro)
export default function App() {
  const [screen, setScreen] = useState("home");
  const [cart, setCart] = useState([]);
  const [orders, setOrders] = useState([]);
  const [pedInfo, setPedInfo] = useState({ entrega:"", hora:"", obs:"", regiao:null, enderecoEntrega:"" });

  return (
    <div className="App">
       <style>{CSS}</style>

       {screen === "home" && (
         <Home 
           NOME_APP={NOME_APP}
           cart={cart}
           setScreen={setScreen}
           onPedido={() => setScreen("pedido-info")}
           onLogin={() => console.log("Login...")}
         />
       )}

       {screen === "pedido-info" && (
         <PedidoInfo 
            pedInfo={pedInfo}
            setPedInfo={setPedInfo}
            onBack={() => setScreen("home")}
            onProximo={() => console.log("Indo para o carrinho...")}
         />
       )}
    </div>
  );
}

// 2. COMPONENTES (Todos fora da função App)

export function Home({ onLogin, onPedido, NOME_APP, cart, setScreen }) {
  return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <header style={{ background:"#fff",borderBottom:"2px solid #FFF0F8",padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center" }}>
        <span style={{ fontSize:22,fontWeight:900,color:"#E91E8C",cursor:"pointer" }}>{NOME_APP}</span>
        <div style={{ color:"#E91E8C" }} onClick={() => cart.length > 0 ? setScreen("pedido-cart") : null}>
          🛒 {cart.length}
        </div>
      </header>
      <div style={{ padding:"20px 18px" }}>
        <h2>Bem-vinda!</h2>
        <button onClick={onPedido}>🎂 Fazer Pedido</button>
        <button onClick={onLogin}>👤 Entrar</button>
      </div>
    </div>
  );
}

export function PedidoInfo({ pedInfo, setPedInfo, onBack, onProximo }) {
  return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <Hdr title="📅 Dados do pedido" onBack={onBack} />
      <div style={{ padding:18, maxWidth:500, margin:"0 auto" }}>
        <Fld label="Data de entrega">
           <input type="date" value={pedInfo.entrega} onChange={e => setPedInfo({...pedInfo, entrega: e.target.value})} style={{width:"100%", padding:"10px", borderRadius:10, border:"1px solid #E5D0EE"}} />
        </Fld>
        <Fld label="Observações">
           <input value={pedInfo.obs} onChange={e => setPedInfo({...pedInfo, obs: e.target.value})} style={{width:"100%", padding:"10px", borderRadius:10, border:"1px solid #E5D0EE"}} />
        </Fld>
        <Btn ch="Montar meu pedido →" onClick={onProximo} />
      </div>
    </div>
  );
}

export function Hdr({ title, onBack }) {
  return (
    <div style={{ padding:"12px 16px", display:"flex", alignItems:"center", borderBottom:"1px solid #E5D0EE" }}>
      <button onClick={onBack} style={{ border:"none", background:"none", fontSize:20 }}>←</button>
      <span style={{ fontWeight:900, marginLeft:10 }}>{title}</span>
    </div>
  );
}

export function Fld({ label, children }) {
  return (
    <div style={{ marginBottom: 12 }}>
      <label style={{ fontSize:13, fontWeight:700, display:"block", marginBottom:4 }}>{label}</label>
      {children}
    </div>
  );
}

export function Btn({ ch, onClick }) {
  return <button onClick={onClick} style={{ width:"100%", padding:15, background:"#E91E8C", color:"#fff", border:"none", borderRadius:10, fontWeight:800 }}>{ch}</button>;
}
